SELECT icon_name
FROM icon_metadata
WHERE icon_size_id = 0;

SELECT project_name
FROM projects
ORDER BY project_name;

SELECT icon_name, icon_description, icon_size_id
FROM icon_metadata
WHERE icon_metadata_id = 1;

SELECT COUNT(icon_size_id) AS icon_size_count
FROM icon_sizes
WHERE icon_type_id = 0;

SELECT COUNT(icon_metadata_id) AS icon_count
FROM icon_metadata
WHERE icon_size_id = 0;

SELECT icon_type_id, COUNT(*) AS total_icon_sizes
FROM icon_sizes
GROUP BY icon_type_id;
